from semantic_kernel.planners import ActionPlanner

async def repair_plan(plan, kernel):
    valid_functions = {f.name for f in kernel.functions.get_functions()}

    for i, step in enumerate(plan._steps):
        if step.function.name not in valid_functions:
            # Replace with closest valid function
            similar_func = min(valid_functions, key=lambda x: sum(a==b for a,b in zip(step.function.name, x)))
            step.function = kernel.functions.get_function(similar_func)
            print(f"Repaired {step.function.name} -> {similar_func}")

plan = await repair_plan(plan, kernel)
